// Bounded buffer (producer/consumer) with a mutex + two condition variables
#define N 16
int buf[N], count = 0, head = 0, tail = 0;
pthread_mutex_t m = PTHREAD_MUTEX_INITIALIZER;
pthread_cond_t not_full  = PTHREAD_COND_INITIALIZER;
pthread_cond_t not_empty = PTHREAD_COND_INITIALIZER;

void produce(int item) {
    pthread_mutex_lock(&m);
    while (count == N)                          // WHILE, not if: guard against spurious wakeups
        pthread_cond_wait(&not_full, &m);       // atomically unlocks m and sleeps
    buf[tail] = item; tail = (tail + 1) % N; count++;
    pthread_cond_signal(&not_empty);            // wake a waiting consumer
    pthread_mutex_unlock(&m);
}

int consume(void) {
    pthread_mutex_lock(&m);
    while (count == 0)
        pthread_cond_wait(&not_empty, &m);
    int item = buf[head]; head = (head + 1) % N; count--;
    pthread_cond_signal(&not_full);
    pthread_mutex_unlock(&m);
    return item;
}

// Deadlock: two threads acquire two locks in OPPOSITE orders -> circular wait
// Thread A: lock(L1); lock(L2);   Thread B: lock(L2); lock(L1);

// Prevention by GLOBAL LOCK ORDERING: always lock lower id first
void transfer(Account a, Account b, long amount) {
    Account first  = a.id < b.id ? a : b;   // canonical order breaks circular wait
    Account second = a.id < b.id ? b : a;
    synchronized (first) {
        synchronized (second) {
            a.balance -= amount;
            b.balance += amount;
        }
    }
}

