import java.util.concurrent.locks.*;

public class BoundedBuffer<T> {
    private final Object[] buf;
    private int count = 0, head = 0, tail = 0;
    private final ReentrantLock lock = new ReentrantLock();
    private final Condition notFull  = lock.newCondition();
    private final Condition notEmpty = lock.newCondition();

    public BoundedBuffer(int capacity) { this.buf = new Object[capacity]; }

    public void put(T item) throws InterruptedException {
        lock.lock();
        try {
            while (count == buf.length)      // while, not if: guard recheck + spurious wakeups
                notFull.await();             // atomically releases lock and sleeps
            buf[tail] = item;
            tail = (tail + 1) % buf.length;
            count++;
            notEmpty.signal();               // a consumer may now proceed
        } finally {
            lock.unlock();
        }
    }

    @SuppressWarnings("unchecked")
    public T take() throws InterruptedException {
        lock.lock();
        try {
            while (count == 0)
                notEmpty.await();
            T item = (T) buf[head];
            buf[head] = null;                // help GC
            head = (head + 1) % buf.length;
            count--;
            notFull.signal();                // a producer may now proceed
            return item;
        } finally {
            lock.unlock();
        }
    }
}

public class Bank {
    static class Account {
        final long id;
        final Object lock = new Object();
        long balance;
        Account(long id, long balance) { this.id = id; this.balance = balance; }
    }

    public void transfer(Account from, Account to, long amount) {
        if (from.id == to.id) return;                 // nothing to do; avoid self-deadlock

        // Global lock ordering by id breaks the circular-wait condition.
        Account first  = from.id < to.id ? from : to;
        Account second = from.id < to.id ? to   : from;

        synchronized (first.lock) {
            synchronized (second.lock) {
                if (from.balance < amount)
                    throw new IllegalStateException("insufficient funds");
                from.balance -= amount;
                to.balance   += amount;
            }
        }
    }
}
